use std::fs::File;
use std::io::{self, BufReader, BufWriter, Write, BufRead};

struct Record {
    id: String,
    content: Vec<u8>,
}

fn main() -> io::Result<()>{
    let input_path = "input.txt";
    let output_path = "output.txt";

    std::fs::write(input_path, b"Header linenRecoord A datanJunk line that should be ignorednRecoord B data with more stuffn");

    let file = File::open(input_path)?; 
    let reader = BufReader::new(file);
