use std::fs::File;
use std::io::{self, Write};
use std::path::Path;

fn process_and_write(input_paths: &[String], output_dir: &str) -> io::Result<()> {
    let output_path = Path::new(output_dir);
    if !output_path.exists() {
        std::fs::create_dir_all(output_path)?; 
    }

    for input_file in input_paths {
        let output_file_name = format!("{}_processed.txt", Path::new(input_file).file_stem().unwrap().to_str().unwrap());
        let output_full_path = output_path.join(&output_file_name);

        let mut file: File = File::create(&output_full_path)?;
        writeln!(file, "Successfully processed data for {}", input_file)?; 
        writeln!(file, "This content was written by the main executable.")?;
    }

    println!("Finished writing to directory: {}", output_dir);
    Ok(())
}

fn main() -> io::Result<()> {
    let files_to_process = vec![String::from("data1.log"), String::from("config/settings.dat")];
    let temp_output_directory = "extension_results";

    if let Err(e) = process_and_write(&files_to_process, temp_output_directory) {
        eprintln!("An error occurred: {}", e);
    }

    Ok(())
}
